#include <bits/stdc++.h>
using namespace std;
const int N=1e5+10;
int n,q,a[N],b[N];
int main(){
    int t;
    scanf("%d",&t);
    while(t--){
        map<int,int> id;
		vector<int> num[N];
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i]);
            b[i]=a[i];
        }
        sort(b+1,b+n+1);
        for(int i=1;i<=n;i++)
            if(!id[b[i]])
                id[b[i]]=i;
        for(int i=1;i<=n;i++)
            a[i]=id[a[i]],num[a[i]].push_back(i);
        scanf("%d",&q);
        while(q--){
            int l,r,x;
            scanf("%d%d%d",&l,&r,&x);
            x=id[x];
            int len=num[x].size(),left=0,right=len-1;
            if(!len){
                printf("0\n");
                continue;
            }
            while(left<right){
                int mid=(left+right)/2;
                if(num[x][mid]<l)
                    left=mid+1;
                else if(num[x][mid]>r)
                    right=mid-1;
                else
                    right=mid;
            }
            if(num[x][right]<l || num[x][right]>r){
                printf("0\n");
                continue;
            }
            int tmp=right;
            left=0,right=len-1;
            while(left<right){
                int mid=(left+right+1)/2;
                if(num[x][mid]<l)
                    left=mid+1;
                else if(num[x][mid]>r)
                    right=mid-1;
                else
                    left=mid;
            }
            tmp=left-tmp+1;
            printf("%d\n",tmp);
        }
    }
    return 0;
}
